#define BENCHMARK_FOR_ALL_TYPES(function_name) \
    BENCHMARK_TEMPLATE(function_name, uint128_t)->UseManualTime()->Iterations(10000); \
    BENCHMARK_TEMPLATE(function_name, int128_t)->UseManualTime()->Iterations(10000); \
    BENCHMARK_TEMPLATE(function_name, uint256_t)->UseManualTime()->Iterations(10000); \
    BENCHMARK_TEMPLATE(function_name, int256_t)->UseManualTime()->Iterations(10000)

BENCHMARK_FOR_ALL_TYPES(bench_add_simple);
BENCHMARK_FOR_ALL_TYPES(bench_add_carry);
BENCHMARK_FOR_ALL_TYPES(bench_sub_simple);
BENCHMARK_FOR_ALL_TYPES(bench_sub_borrow);
BENCHMARK_FOR_ALL_TYPES(bench_mul_dense);
BENCHMARK_FOR_ALL_TYPES(bench_div_dense);
BENCHMARK_FOR_ALL_TYPES(bench_mod_dense);
BENCHMARK_FOR_ALL_TYPES(bench_eq_equal);
BENCHMARK_FOR_ALL_TYPES(bench_lt_less);
BENCHMARK_FOR_ALL_TYPES(bench_shl_small_shift);
BENCHMARK_FOR_ALL_TYPES(bench_shl_word_crossing_shift);
BENCHMARK_FOR_ALL_TYPES(bench_shr_small_shift);
BENCHMARK_FOR_ALL_TYPES(bench_shr_word_crossing_shift);

#undef BENCHMARK_FOR_ALL_TYPES
